      "path": "src/modules/members/service.js",
      "content": "const projectsService = require('../projects/service');

function addMember(projectId, userId, role) {
  // Check for duplicate members within the project
  const project = projectsService.getProjectById(projectId);
  if (!project) throw new NotFoundError('Project not found');
  if (project.members.some(member => member.userId === userId)) {
    throw new BadRequestError('Member already exists in this project');
  }
  // Add the member to the project
  project.members.push({ userId, role });
}

exports.addMember = addMember;"
