      "path": "src/modules/tasks/service.js",
      "content": "const projectsService = require('../projects/service');

function createTask(projectId, taskData) {
  const project = projectsService.getProjectById(projectId);
  if (!project) throw new NotFoundError('Project not found');
  taskData.status = 'todo'; // Default status is todo
  project.tasks.push(taskData);
}

function updateTaskStatus(projectId, taskId, newStatus) {
  const project = projectsService.getProjectById(projectId);
  if (!project) throw new NotFoundError('Project not found');
  const task = project.tasks.find(task => task.id === taskId);
  if (!task) throw new NotFoundError('Task not found');
  if (newStatus !== 'todo' && newStatus !== 'done') {
    throw new BadRequestError('Invalid task status');
  }
  task.status = newStatus;
}

function getTasksByProjectId(projectId) {
  const project = projectsService.getProjectById(projectId);
  if (!project) throw new NotFoundError('Project not found');
  return project.tasks.filter(task => task.status === 'done');
}

exports.createTask = createTask;
exports.updateTaskStatus = updateTaskStatus;
exports.getTasksByProjectId = getTasksByProjectId;"
